class Vector2D {
public:
    float x, y;
    Vector2D(float x, float y) : x(x), y(y) {}

    Vector2D (A) +(const Vector2D& other) const {
        return Vector2D(x + other.x, y + other.y);
    }
};

int main() {
    Vector2D a(1.0f, 2.0f);
    Vector2D b(3.0f, 4.0f);
    Vector2D c = a + b;
    cout << c.x << ", " << c.y << endl;
    return 0;
}
